commonMistakes.codeArabic:
// ❌ خطأ: هذا لا يعني (0 < x) و (x < 10)
if (0 < x < 10) { /* ... */ }
// ما يحدث فعليًا: (0 < x) يُرجع 0 أو 1، ثم يُقارن بـ 10
// فإذا x = 5: (0 < 5) = 1، ثم 1 < 10 = true — بالصدفة!
// لكن إذا x = -1: (0 < -1) = 0، ثم 0 < 10 = true — خطأ!

// ✅ الصحيح: فصل المقارنتين
if (x > 0 && x < 10) { /* ... */ }

// ❌ خطأ: إسناد داخل if لا مقارنة
if (x = 5) { /* سينفذ دائمًا لأن 5 != 0 */ }

// ✅ الصحيح: مقارنة
if (x == 5) { /* ... */ }

// ✅ حيلة دفاعية: ضع الثابت أولًا
if (5 == x) { /* إذا كتبت = بالخطأ سيفشل الترجمة */ }

// ❌ خطأ: == أسبقية أعلى من &
if (flags & mask == 0) { /* ... */ }
// يُقرأ كـ: flags & (mask == 0)
// أي: flags & 1 أو flags & 0 حسب نتيجة المقارنة

// ✅ الصحيح: أقواس واضحة
if ((flags & mask) == 0) { /* ... */ }

int shifted = value << 3;   // ✅ إزاحة بتات: value × 8
std::cout << value;          // ✅ إرسال للتدفق: طباعة

// لكن داخل تعبير مختلط:
// std::cout << value << 3; // لا يعني إزاحة! يطبع value ثم 3

// ✅ إذا أردت الطباعة بعد الإزاحة:
std::cout << (value << 3);
